# Validate plugin filename - must be whitelisted
sub validate_plugin_name {
    my ($name) = @_;

    # Only allow whitelisted filenames
    unless (exists $ALLOWED_PLUGINS{$name}) {
        log_event('REJECT', "Plugin '$name' is not in the whitelist");
        return 0;
    }

    # Ensure no path traversal
    if ($name =~ m{[/\\]} || $name =~ m{\.\.}) {
        log_event('REJECT', "Plugin '$name' contains path traversal characters");
        return 0;
    }

    # Only allow .pl extension
    unless ($name =~ /^[a-zA-Z0-9_]+\.pl$/) {
        log_event('REJECT', "Plugin '$name' has invalid characters or extension");
        return 0;
    }

    return 1;
}

# Validate plugin code content for dangerous patterns
sub validate_plugin_code {
    my ($code, $plugin_name) = @_;

    for my $pattern (@FORBIDDEN_PATTERNS) {
        if ($code =~ $pattern) {
