            return 0;
        }
    }

    # Check for null bytes
    if ($code =~ /\0/) {
        log_event('REJECT', "Plugin '$plugin_name' contains null bytes");
        return 0;
    }

    return 1;
}

# Read plugin file securely
sub read_plugin_file {
    my ($plugin_name) = @_;

    return undef unless validate_plugin_name($plugin_name);

    my $filepath = "$PLUGIN_DIR/$plugin_name";

    # Verify the file exists and is a regular file
    unless (-f $filepath && -r $filepath) {
        log_event('ERROR', "Plugin file '$filepath' does not exist or is not readable");
        return undef;
    }

    # Check file is not a symlink (prevent symlink attacks)
    if (-l $filepath) {
        log_event('REJECT', "Plugin file '$filepath' is a symlink - rejected");
        return undef;
    }

    # Check file size
    my $file_size = -s $filepath;
    if ($file_size > $MAX_PLUGIN_SIZE) {
        log_event('REJECT', "Plugin '$plugin_name' exceeds max size ($file_size > $MAX_PLUGIN_SIZE)");
        return undef;
    }

    # Check file ownership and permissions
    my @stat = stat($filepath);
    my $mode = $stat[2] & 07777;

    # File should not be world-writable
    if ($mode & 002) {
        log_event('REJECT', "Plugin '$plugin_name' is world-writable (mode: " . sprintf("%04o", $mode) . ")");
        return undef;
    }

    # Read the file
    open my $fh, '<', $filepath or do {
        log_event('ERROR', "Cannot open plugin '$filepath': $!");
        return undef;
    };

    local $/;
    my $code = <$fh>;
    close $fh;

    return $code;
}

# Execute plugin code in a restricted namespace
sub execute_plugin {
    my ($plugin_name, $input_data) = @_;

    log_event('INFO', "Loading plugin '$plugin_name'");

    # Read the plugin code
    my $plugin_code = read_plugin_file($plugin_name);
    unless (defined $plugin_code) {
        log_event('ERROR', "Failed to load plugin '$plugin_name'");
        return { success => 0, error => "Failed to load plugin" };
    }

    # Validate code content
    unless (validate_plugin_code($plugin_code, $plugin_name)) {
        log_event('REJECT', "Plugin '$plugin_name' failed code validation");
        return { success => 0, error => "Plugin code validation failed" };
    }

    log_event('INFO', "Executing plugin '$plugin_name' (" . length($plugin_code) . " bytes)");

    # Wrap plugin code in a restricted package namespace
    # The plugin receives $input and must set $output
    my $wrapped_code = qq{
        package PluginSandbox::$plugin_name;
        no strict 'refs';
        sub run_plugin {
            my (\$input) = \@_;
            my \$output = {};
            $plugin_code
            return \$output;
        }
        1;
    };

    # Clean the package name (remove .pl extension and special chars)
    my $clean_name = $plugin_name;
    $clean_name =~ s/[^a-zA-Z0-9_]/_/g;
    $wrapped_code =~ s/PluginSandbox::$plugin_name/PluginSandbox::$clean_name/g;

    # Set alarm to prevent infinite loops
    my $result;
    my $eval_error;

    local $SIG{ALRM} = sub { die "Plugin execution timed out\n" };
    alarm(5);  # 5-second timeout

    eval {
        # Compile the plugin
        eval($wrapped_code);  ## no critic - intentional dynamic code execution for plugin system
        if ($@) {
            die "Plugin compilation error: $@";
        }

        # Call the plugin's run function
        my $run_func = "PluginSandbox::${clean_name}::run_plugin";
        {
            no strict 'refs';
            $result = $run_func->($input_data);
        }
    };
    $eval_error = $@;

    alarm(0);  # Cancel alarm

    if ($eval_error) {
        log_event('ERROR', "Plugin '$plugin_name' execution failed: $eval_error");
        return { success => 0, error => "Plugin execution error: $eval_error" };
    }

    log_event('INFO', "Plugin '$plugin_name' executed successfully");
    return { success => 1, data => $result };
}

